internal static bool IsInTerminalStatus(DagExecutionStatus status)
{
    return (status == DagExecutionStatus.Completed)
        || (status == DagExecutionStatus.Failed)
        || (status == DagExecutionStatus.Skipped)
        || (status == DagExecutionStatus.Cancelled);
}

/// Feature flag to control cleaning up for TokenManager on DAG completion.
/// Kill-switch: enable to revert to old behavior (always update, never delete). To be removed once validated in production.
